#@category Imperialism
# Export local Ghidra data types into split C headers.
#
# Supported runtime:
# - Ghidra 12.0.2 PUBLIC only
#
# Output layout:
# - arg[0] or directory chooser target
# - one generated .h per datatype category bucket
# - all_types.h umbrella include
# - _manifest.json tracks generated files for stale cleanup
# - index.csv maps datatype path to header file

import json
import os
import re

from java.io import StringWriter
from java.util import ArrayList

from ghidra.framework import Application
from ghidra.program.model.data import (
    DataTypeWriter,
    Enum,
    FunctionDefinition,
    Structure,
    TypeDef,
    Union,
)

EXPECTED_GHIDRA_VERSION = "12.0.2"
EXPECTED_GHIDRA_RELEASE = "PUBLIC"

MANIFEST_BASENAME = "_manifest.json"
INDEX_BASENAME = "index.csv"
ALL_TYPES_BASENAME = "all_types.h"


def enforce_ghidra_version():
    actual_version = Application.getApplicationVersion()
    actual_release = Application.getApplicationReleaseName()
    if (
        actual_version != EXPECTED_GHIDRA_VERSION
        or actual_release != EXPECTED_GHIDRA_RELEASE
    ):
        raise RuntimeError(
            "Unsupported Ghidra runtime: {} {}. Expected {} {}.".format(
                actual_version,
                actual_release,
                EXPECTED_GHIDRA_VERSION,
                EXPECTED_GHIDRA_RELEASE,
            )
        )


def normalize_relpath(relpath):
    return relpath.replace("\\", "/")


def safe_join(base_dir, relpath):
    rel = normalize_relpath(relpath)
    parts = [p for p in rel.split("/") if p]
    if rel.startswith("/") or ".." in parts:
        raise RuntimeError("Unsafe relative path: {}".format(relpath))
    return os.path.join(base_dir, *parts)


def write_bytes(path, data):
    parent = os.path.dirname(path)
    if parent and not os.path.isdir(parent):
        os.makedirs(parent)
    with open(path, "wb") as fd:
        fd.write(data)


def sanitize_path_component(name):
    value = re.sub(r"[^A-Za-z0-9._-]+", "_", name)
    value = re.sub(r"_+", "_", value).strip("._")
    if not value:
        return "unnamed"
    return value


def load_old_files(manifest_path):
    if not os.path.isfile(manifest_path):
        return []
    try:
        with open(manifest_path, "rb") as fd:
            payload = json.loads(fd.read().decode("utf-8"))
        return list(payload.get("generated_header_files", []))
    except Exception as exc:
        print("Warning: could not read previous manifest {}: {}".format(manifest_path, exc))
        return []


def remove_old_generated_files(base_dir, old_files):
    for rel in old_files:
        try:
            full = safe_join(base_dir, rel)
        except Exception:
            continue
        if os.path.isfile(full):
            os.remove(full)


def remove_empty_dirs(root_dir):
    for cur, dirs, files in os.walk(root_dir, topdown=False):
        if cur == root_dir:
            continue
        if dirs or files:
            if os.listdir(cur):
                continue
        os.rmdir(cur)


def dtype_kind(dt):
    if isinstance(dt, Structure):
        return "structure"
    if isinstance(dt, Union):
        return "union"
    if isinstance(dt, Enum):
        return "enum"
    if isinstance(dt, TypeDef):
        return "typedef"
    if isinstance(dt, FunctionDefinition):
        return "function_definition"
    return "other"


def should_export_dtype(dt):
    return (
        isinstance(dt, Structure)
        or isinstance(dt, Union)
        or isinstance(dt, Enum)
        or isinstance(dt, TypeDef)
        or isinstance(dt, FunctionDefinition)
    )


def category_to_base_relpath(category_path):
    if category_path is None or category_path.isRoot():
        return "root_types.h"
    elems = [sanitize_path_component(x) for x in category_path.asList()]
    return "/".join(elems) + ".h"


def dedupe_relpath(base_relpath, used_relpaths):
    if base_relpath not in used_relpaths:
        used_relpaths.add(base_relpath)
        return base_relpath

    base_dir = os.path.dirname(base_relpath)
    base_name = os.path.basename(base_relpath)
    if base_name.lower().endswith(".h"):
        stem = base_name[:-2]
    else:
        stem = base_name

    idx = 2
    while True:
        cand_name = "{}_{}.h".format(stem, idx)
        candidate = cand_name if not base_dir else base_dir + "/" + cand_name
        if candidate not in used_relpaths:
            used_relpaths.add(candidate)
            return candidate
        idx += 1


def render_header_text(program_name, category_path_text, data_types, dtm):
    arr = ArrayList()
    for dt in data_types:
        arr.add(dt)

    sw = StringWriter()
    writer = DataTypeWriter(dtm, sw, True)
    writer.write(arr, monitor)
    rendered = sw.toString()

    out = []
    out.append("// AUTOGENERATED FROM GHIDRA. DO NOT EDIT.\n")
    out.append("// Script: ExportTypeHeaders_Split.py\n")
    out.append("// Program: {}\n".format(program_name))
    out.append("// Category: {}\n\n".format(category_path_text))
    out.append("#pragma once\n\n")
    out.append(rendered)
    if not rendered.endswith("\n"):
        out.append("\n")
    return "".join(out)


enforce_ghidra_version()

args = getScriptArgs()
if args is not None and len(args) >= 1 and args[0]:
    out_dir = args[0]
else:
    out_dir = askDirectory("Export type headers directory...", "Select").absolutePath

out_dir = os.path.abspath(out_dir)
if not os.path.isdir(out_dir):
    os.makedirs(out_dir)

manifest_path = os.path.join(out_dir, MANIFEST_BASENAME)
index_path = os.path.join(out_dir, INDEX_BASENAME)
all_types_path = os.path.join(out_dir, ALL_TYPES_BASENAME)

old_files = load_old_files(manifest_path)
remove_old_generated_files(out_dir, old_files)

dtm = currentProgram.getDataTypeManager()
local_archive = dtm.getLocalSourceArchive()
local_data_types = dtm.getDataTypes(local_archive)

# Bucket by category path.
buckets = {}
skipped_non_matching = 0
for dt in local_data_types:
    if not should_export_dtype(dt):
        skipped_non_matching += 1
        continue

    cp = dt.getCategoryPath()
    cp_text = cp.getPath() if cp is not None else "/"
    if cp_text not in buckets:
        buckets[cp_text] = {"path_obj": cp, "types": []}
    buckets[cp_text]["types"].append(dt)

used_relpaths = set()
generated_files = []
index_rows = ["category|datatype|kind|header"]
count_total_types = 0

for cp_text in sorted(buckets.keys()):
    bucket = buckets[cp_text]
    types = bucket["types"]
    types.sort(key=lambda d: d.getName().lower())

    rel_base = category_to_base_relpath(bucket["path_obj"])
    relpath = dedupe_relpath(rel_base, used_relpaths)

    try:
        text = render_header_text(
            currentProgram.getName(),
            cp_text,
            types,
            dtm,
        )
    except Exception as exc:
        print("Skipping category {} due to writer failure: {}".format(cp_text, exc))
        continue

    write_bytes(safe_join(out_dir, relpath), text.encode("utf-8"))
    generated_files.append(normalize_relpath(relpath))

    for dt in types:
        kind = dtype_kind(dt)
        dtype_path = dt.getPathName()
        index_rows.append("{}|{}|{}|{}".format(cp_text, dtype_path, kind, relpath))
        count_total_types += 1

# Umbrella include.
all_types_lines = []
all_types_lines.append("// AUTOGENERATED FROM GHIDRA. DO NOT EDIT.\n")
all_types_lines.append("#pragma once\n\n")
for rel in sorted(generated_files):
    all_types_lines.append('#include "{}"\n'.format(rel))
write_bytes(all_types_path, "".join(all_types_lines).encode("utf-8"))

# Index + manifest.
write_bytes(index_path, ("\n".join(index_rows) + "\n").encode("utf-8"))

manifest_payload = {
    "generated_header_files": sorted(generated_files + [ALL_TYPES_BASENAME]),
    "program": currentProgram.getName(),
    "category_count": len(generated_files),
    "type_count": count_total_types,
}
write_bytes(
    manifest_path,
    (json.dumps(manifest_payload, indent=2, sort_keys=True) + "\n").encode("utf-8"),
)

remove_empty_dirs(out_dir)

print("Wrote {} headers under {}".format(len(generated_files), out_dir))
print("Wrote umbrella header: {}".format(all_types_path))
print("Types exported: {}".format(count_total_types))
print("Skipped non-selected datatypes: {}".format(skipped_non_matching))
print("Index: {}".format(index_path))
print("Manifest: {}".format(manifest_path))
